import OpenAI from 'openai';
import { VexClient } from 'vex-sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

const app = express();

app.post('/webhook/run-completed', async (req, res) => {
  const { data: run } = req.body;

  const thread = await openai.beta.threads.retrieve(run.thread_id);
  const messages = await openai.beta.threads.messages.list(run.thread_id);
  const lastMessage = messages.data[0];

  const verification = await vex.verify({
    prompt: lastMessage.content[0].text.value,
    response: run.last_error || run.required_action?.submit_tool_outputs?.tool_calls[0]?.function?.arguments,
    policy: 'ecommerce',
    checks: ['no_hallucinated_pricing', 'substantiated_claims', 'no_pii']
  });

  if (!verification.passed && run.status === 'requires_action') {
    await openai.beta.threads.runs.submitToolOutputs(run.thread_id, run.id, [{
      tool_call_id: run.required_action.submit_tool_outputs.tool_calls[0].id,
      output: JSON.stringify({ blocked: verification.violations })
    }]);
  }

  res.status(200).send('OK');
});

app.listen(3000);
